#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007

int maxSubmatrixSum(int*** matrix, int* sizes, int N) {
    int maxSum = -1000000000;
    int count = 0;
    // Generate all possible submatrices and calculate their sums
    for (int i1 = 0; i1 < sizes[0]; i1++) {
        for (int j1 = i1; j1 < sizes[0]; j1++) {
            for (int i2 = 0; i2 < sizes[1]; i2++) {
                for (int j2 = i2; j2 < sizes[1]; j2++) {
                    // ... and so on for all N lists
                    int sum = 0;
                    for (int k1 = i1; k1 <= j1; k1++) {
                        for (int k2 = i2; k2 <= j2; k2++) {
                            // ... and so on for all N lists
                            sum += matrix[k1][k2];
                        }
                    }
                    if (sum > maxSum) {
                        maxSum = sum;
                        count = 1;
                    } else if (sum == maxSum) {
                        count = (count + 1) % MOD;
                    }
                }
            }
        }
    }
    printf("%d %d\n", maxSum, count);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int* sizes = (int*)malloc(N * sizeof(int));
        int*** matrix = (int***)malloc(N * sizeof(int**));
        for (int i = 0; i < N; i++) {
            scanf("%d", &sizes[i]);
            matrix[i] = (int**)malloc(sizes[i] * sizeof(int*));
            for (int j = 0; j < sizes[i]; j++) {
                matrix[i][j] = (int*)malloc(sizes[i] * sizeof(int));
                for (int k = 0; k < sizes[i]; k++) {
                    scanf("%d", &matrix[i][j][k]);
                }
            }
        }
        maxSubmatrixSum(matrix, sizes, N);
    }
    return 0;
}

